package mcp

import (
	"os"
	"strings"
	"testing"
)

func TestMutationToolsAreDestructive(t *testing.T) {
	src, err := os.ReadFile("tools.go")
	if err != nil {
		t.Fatalf("read tools.go: %v", err)
	}
	text := string(src)
	for _, tool := range []string{
		"dns_set-custom",
		"dns_set-default",
		"dns_set-hosts",
		"domains_create",
		"domains_renew",
		"domains_set-registrar-lock",
	} {
		idx := strings.Index(text, `mcplib.NewTool("`+tool+`"`)
		if idx == -1 {
			t.Fatalf("missing MCP tool %s", tool)
		}
		end := strings.Index(text[idx:], "),\n\t\tmakeAPIHandler")
		if end == -1 {
			t.Fatalf("could not find MCP registration block for %s", tool)
		}
		block := text[idx : idx+end]
		if !strings.Contains(block, "mcplib.WithReadOnlyHintAnnotation(false)") {
			t.Fatalf("%s is not marked non-read-only", tool)
		}
		if !strings.Contains(block, "mcplib.WithDestructiveHintAnnotation(true)") {
			t.Fatalf("%s is not marked destructive", tool)
		}
	}
}
